"""Tests for v2 derived id functions (process_id, epoch_id).

The hashes are deterministic projections of log content. Same logs in →
same ids out. Documented in docs/design/api.md.
"""

import hashlib

from agentpulse.api.v2.ids import derive_epoch_id, derive_process_id


class TestProcessId:
    def test_deterministic(self) -> None:
        a = derive_process_id(
            source_system="host", pid=1234, cwd="/proj", earliest_received_at=100.5
        )
        b = derive_process_id(
            source_system="host", pid=1234, cwd="/proj", earliest_received_at=100.5
        )
        assert a == b

    def test_length_16(self) -> None:
        pid = derive_process_id(
            source_system="host", pid=1234, cwd="/proj", earliest_received_at=100.5
        )
        assert len(pid) == 16

    def test_floors_subsecond(self) -> None:
        """Subsecond differences in earliest_received_at don't change the id.

        Per api.md: the timestamp is floored to seconds before hashing.
        """
        a = derive_process_id(
            source_system="host", pid=1234, cwd="/proj", earliest_received_at=100.0
        )
        b = derive_process_id(
            source_system="host", pid=1234, cwd="/proj", earliest_received_at=100.999
        )
        assert a == b

    def test_pid_reuse_produces_different_id(self) -> None:
        """Same pid/cwd at different times → different process_id."""
        a = derive_process_id(
            source_system="host", pid=1234, cwd="/proj", earliest_received_at=100.0
        )
        b = derive_process_id(
            source_system="host", pid=1234, cwd="/proj", earliest_received_at=200.0
        )
        assert a != b

    def test_different_cwd_different_id(self) -> None:
        a = derive_process_id(
            source_system="host", pid=1234, cwd="/a", earliest_received_at=100.0
        )
        b = derive_process_id(
            source_system="host", pid=1234, cwd="/b", earliest_received_at=100.0
        )
        assert a != b

    def test_matches_documented_algorithm(self) -> None:
        """Lock the wire format: source_system|pid|cwd|epoch_int."""
        expected = hashlib.sha256(b"host|1234|/proj|100").hexdigest()[:16]
        actual = derive_process_id(
            source_system="host", pid=1234, cwd="/proj", earliest_received_at=100.5
        )
        assert actual == expected


class TestEpochId:
    def test_deterministic(self) -> None:
        a = derive_epoch_id(
            session_id="s1",
            pid=1234,
            source_system="host",
            cwd="/proj",
            earliest_received_at=100.5,
        )
        b = derive_epoch_id(
            session_id="s1",
            pid=1234,
            source_system="host",
            cwd="/proj",
            earliest_received_at=100.5,
        )
        assert a == b

    def test_length_16(self) -> None:
        eid = derive_epoch_id(
            session_id="s1",
            pid=1234,
            source_system="host",
            cwd="/proj",
            earliest_received_at=100.5,
        )
        assert len(eid) == 16

    def test_resume_into_new_pid_different_id(self) -> None:
        """Same session_id, different pid → different epoch_id."""
        a = derive_epoch_id(
            session_id="s1",
            pid=1234,
            source_system="host",
            cwd="/proj",
            earliest_received_at=100.0,
        )
        b = derive_epoch_id(
            session_id="s1",
            pid=5678,
            source_system="host",
            cwd="/proj",
            earliest_received_at=200.0,
        )
        assert a != b

    def test_matches_documented_algorithm(self) -> None:
        expected = hashlib.sha256(b"s1|1234|host|/proj|100").hexdigest()[:16]
        actual = derive_epoch_id(
            session_id="s1",
            pid=1234,
            source_system="host",
            cwd="/proj",
            earliest_received_at=100.5,
        )
        assert actual == expected


class TestProcessIdNotEpochId:
    """Sanity: process_id and epoch_id over the same identity must differ.

    They should — process_id has 4 fields, epoch_id has 5. But pin it.
    """

    def test_distinct_from_epoch_id(self) -> None:
        pid_id = derive_process_id(
            source_system="host", pid=1234, cwd="/proj", earliest_received_at=100.0
        )
        epoch_id = derive_epoch_id(
            session_id="s1",
            pid=1234,
            source_system="host",
            cwd="/proj",
            earliest_received_at=100.0,
        )
        assert pid_id != epoch_id
